Consider the following code. What is the output?

interface Formatter {
    static String format(String s) {
        return "Formatted: " + s.toUpperCase();
    }
}

class Report implements Formatter {}

public class Test {
    public static void main(String[] args) {
        System.out.println(Formatter.format("hello"));
        System.out.println(Report.format("hello"));
    }
}
